import AsyncStorage from '@react-native-async-storage/async-storage';
import aesCrypto from 'react-native-aes-crypto';

export const encryptData = async (key, data) => {
  const encryptedData = await aesCrypto.encrypt(data, encryptionKey);
  await AsyncStorage.setItem(key, encryptedData);
};

export const decryptData = async (key) => {
  const encryptedData = await AsyncStorage.getItem(key);
  const decryptedData = await aesCrypto.decrypt(encryptedData, encryptionKey);
  return decryptedData;
};

